#include <unordered_set>

class Solution {
public:
    int canBeTypedWords(string text, string brokenLetters) {
        unordered_set<char> brokenChars(brokenLetters.begin(), brokenLetters.end());
        int count = 0;
        for (char c : text) {
            if (brokenChars.find(c) == brokenChars.end()) {
                count++;
            }
        }
        return count;
    }
};
```

